def search_attck_crossref(query: str) -> str:
    """Search ATT&CK + threat actor cross-reference data"""
    context_parts = []
    query_lower = query.lower()

    # Search threat actors
    matched_actors = []
    for name, actor in THREAT_ACTORS.items():
        if (query_lower in name.lower() or
            any(query_lower in a.lower() for a in actor.get("aliases", [])) or
            query_lower in actor.get("description", "").lower()):
            matched_actors.append((name, actor))

    # Search ATT&CK techniques
    matched_techniques = []
    for tid, tech in ATTCK_TECHNIQUES.items():
        if (tid.lower() in query_lower or
            query_lower in tech["name"].lower()):
            matched_techniques.append((tid, tech))

    # Search malware
    matched_malware = []
    for name, mal in MALWARE_DB.items():
        if (query_lower in name.lower() or
            query_lower in mal.get("description", "").lower()):
            matched_malware.append((name, mal))

    # Search campaigns
    matched_campaigns = []
    for name, camp in CAMPAIGNS_DB.items():
        if (query_lower in name.lower() or
            query_lower in camp.get("description", "").lower()):
            matched_campaigns.append((name, camp))

    if matched_actors:
        context_parts.append("=== MATCHING THREAT ACTORS ===")
        for name, actor in matched_actors[:10]:
            techs = ", ".join(actor.get("attck_techniques", [])[:10])
            aliases = ", ".join(actor.get("aliases", []))
            context_parts.append(f"{name} ({actor['id']}): {actor['description'][:150]}")
            if aliases:
                context_parts.append(f"  Aliases: {aliases}")
            if techs:
                context_parts.append(f"  ATT&CK Techniques: {techs} ({actor['total_techniques']} total)")

    if matched_techniques:
        context_parts.append("\n=== MATCHING ATT&CK TECHNIQUES ===")
        for tid, tech in matched_techniques[:15]:
            tactics = ", ".join(tech.get("tactics", []))
            context_parts.append(f"{tid} - {tech['name']} (Tactics: {tactics})")

    if matched_malware:
        context_parts.append("\n=== MATCHING MALWARE ===")
        for name, mal in matched_malware[:10]:
            context_parts.append(f"{name} ({mal['id']}): {mal['description'][:120]}")

    if matched_campaigns:
        context_parts.append("\n=== MATCHING CAMPAIGNS ===")
        for name, camp in matched_campaigns[:10]:
            context_parts.append(f"{name} ({camp['id']}): {camp['description'][:120]}")

    return "\n".join(context_parts)
